mapper.update:
UPDATE learning_plan
SET status = #{status},
    title = #{title},
    plan_json = #{planJson, typeHandler=org.congcong.algomentor.agent.persistence.postgres.json.JsonbTypeHandler},
    updated_at = #{updatedAt}
WHERE id = #{id}
  AND user_id = #{userId}

mapper.select:
SELECT COUNT(*)
FROM learning_plan
WHERE user_id = #{userId}

SELECT COUNT(*)
FROM learning_plan
WHERE user_id = #{userId}
  AND status = #{status}

SELECT MAX(created_at)
FROM learning_plan
WHERE user_id = #{userId}

mapper.update:
UPDATE learning_plan_draft
SET confirmed_plan_id = NULL,
    updated_at = NOW()
WHERE user_id = #{userId}
  AND confirmed_plan_id = #{planId}

mapper.delete:
DELETE FROM learning_plan
WHERE id = #{id}
  AND user_id = #{userId}
